import { quote } from "./claim-office.js";

export function runScenario(scenario: any): { results: unknown[] } {
  const results: unknown[] = [];
  let quoteCount = 0;
  for (const step of scenario.steps) {
    if (step.op === "quote") {
      const premium = quote({
        customer: {
          yearsWithMHPCO: scenario.customer.yearsWithMHPCO,
          previousContracts: quoteCount,
        },
        items: step.items,
      });
      results.push({ premium });
      quoteCount += 1;
    }
  }
  return { results };
}
